it("should render custom header month changes in the first month", () => {
  const selected = newDate("2020-01-15");
  const renderCustomHeader = ({
    changeMonth,
  }: ReactDatePickerCustomHeaderProps) => (
    <button className="change-month" onClick={() => changeMonth(5)} />
  );
  const { container } = render(
    <DatePicker
      inline
      monthsShown={2}
      selected={selected}
      renderCustomHeader={renderCustomHeader}
      shouldCloseOnSelect={false}
    />,
  );

  const secondMonthDay = container
    .querySelectorAll(".react-datepicker__month")[1]
    ?.querySelector('[aria-label="Choose Saturday, February 15th, 2020"]');
  expect(secondMonthDay).toBeTruthy();
  fireEvent.click(secondMonthDay!);

  fireEvent.click(safeQuerySelector(container, ".change-month"));

  const months = container.querySelectorAll(".react-datepicker__month");
  expect(months[0]?.getAttribute("aria-label")).toContain("June, 2020");
  expect(months[1]?.getAttribute("aria-label")).toContain("July, 2020");
});
